 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
 5	import { PanelCloseIcon, PanelOpenIcon } from '@patternfly/react-icons';
 6	
 7	type PanelToggleButtonProps = {
 8	  className?: string;
 9	  isOpen: boolean;
10	  toggleDrawer: () => void;
11	};
12	
13	const PanelToggleButton: FC<PanelToggleButtonProps> = ({ className, isOpen, toggleDrawer }) => {
14	  const { t } = useKubevirtTranslation();
15	  return (
16	    <Tooltip content={isOpen ? t('Close') : t('Open')}>
17	      <Button className={className} onClick={toggleDrawer} variant={ButtonVariant.plain}>
18	        {isOpen ? <PanelCloseIcon /> : <PanelOpenIcon />}
19	      </Button>
20	    </Tooltip>
21	  );
22	};
23	
24	export default PanelToggleButton;

